/**
 * Filesystem compensation handler.
 *
 * The legacy handler (defaultCompensation.ts:restoreFromSnapshot) only
 * covered file_write / file_edit / apply_patch / code_fixer / code_refiner
 * via a flat `<path>.atr-snapshot.<actionId>` pattern. This module
 * expands coverage to:
 *
 *   - file_write      → restore from snapshot (or delete if file was new)
 *   - file_edit       → restore from snapshot
 *   - file_append     → restore from snapshot
 *   - file_patch      → restore from snapshot
 *   - apply_patch     → restore from snapshot
 *   - file_delete     → restore from snapshot
 *   - file_move       → restore from snapshot (move back)
 *   - file_copy       → delete the copy (the original is unaffected)
 *   - file_chmod      → restore from snapshot
 *   - file_chown      → restore from snapshot
 *   - mkdir           → rmdir (only if empty)
 *   - rmdir           → mkdir back (best-effort)
 *   - shell_execute   → snapshot ALL files in the working dir before run
 *
 *   The compensation plan is generated by the rollback planner based on
 *   the tool name + args; this handler is the executor.
 *
 *   References:
 *     - Stripe idempotency for the snapshot-id-as-idempotency-key pattern:
 *       https://stripe.com/blog/idempotency
 *     - Temporal "compensating actions" for the snapshot-before-mutate
 *       requirement:
 *       https://temporal.io/blog/compensating-actions-part-1
 */

import { statSync } from 'node:fs';
import { dirname } from 'node:path';
import type { CompensableAction } from '../../runtime/compensationRegistry';
import type { CompensationHandler } from '../../runtime/compensationRegistry';
import { getSnapshotStore, type SnapshotStore, type FileSnapshot } from './snapshotStore';
import type { CompensationOutcome } from './types';

interface FilesystemArgs {
  path?: string;
  sourcePath?: string;
  destPath?: string;
  // Shell: list of paths to snapshot
  paths?: string[];
}

/**
 * Resolve which path(s) a tool's action affected, given the args.
 * Different tools use different arg names. The planner uses this to
 * figure out what to snapshot.
 */
export function resolveAffectedPaths(toolName: string, args: Record<string, unknown>): string[] {
  const a = args as FilesystemArgs;
  switch (toolName) {
    case 'file_write':
    case 'file_edit':
    case 'file_append':
    case 'file_patch':
    case 'apply_patch':
    case 'code_fixer':
    case 'code_refiner':
    case 'file_delete':
    case 'file_chmod':
    case 'file_chown':
    case 'file_chgrp':
    case 'touch':
      return a.path ? [a.path] : [];
    case 'file_move':
    case 'file_rename': {
      const out: string[] = [];
      if (a.sourcePath) out.push(a.sourcePath);
      if (a.destPath) out.push(a.destPath);
      return out;
    }
    case 'file_copy':
      return a.destPath ? [a.destPath] : [];
    case 'mkdir':
    case 'rmdir':
    case 'mkdir_p':
      return a.path ? [a.path] : [];
    case 'shell_execute':
    case 'python_execute':
      return Array.isArray(a.paths) ? a.paths : [];
    default:
      return [];
  }
}

/**
 * Take a snapshot of all paths affected by a tool call. Returns the
 * snapshot ids. The compensation handler will look them up by
 * actionId to find what to roll back.
 */
export function snapshotToolCall(
  toolName: string,
  args: Record<string, unknown>,
  ctx: { runId: string; actionId: string },
): FileSnapshot[] {
  const store = getSnapshotStore();
  const paths = resolveAffectedPaths(toolName, args);
  if (paths.length === 0) return [];
  if (paths.length === 1) {
    const [p] = paths;
    return [
      store.take({
        runId: ctx.runId,
        actionId: ctx.actionId,
        toolName,
        path: p,
      }),
    ];
  }
  return store.takeGroup({
    runId: ctx.runId,
    actionId: ctx.actionId,
    toolName,
    paths,
  });
}

// ============================================================================
// Compensation handlers — one per tool
// ============================================================================

function restoreFromStore(_action: CompensableAction,
  store: SnapshotStore,
  variant: 'restore' | 'delete' = 'restore',
): CompensationOutcome {
  const snaps = store.findByAction(_action.actionId);
  if (snaps.length === 0) {
    return { success: true, alreadyCompensated: true };
  }

  // Single path: use the per-action restore path.
  if (snaps.length === 1 && variant === 'restore') {
    const r = store.restore(snaps[0].id);
    if (r.success) return { success: true };
    return { success: false, error: r.error, permanent: false };
  }

  // Group restore: roll back in reverse order.
  const groupIds = Array.from(new Set(snaps.map((s) => s.groupId)));
  let lastError: string | undefined;
  for (const gid of groupIds) {
    const res = store.restoreGroup(gid);
    for (const f of res.failed) {
      lastError = f.error;
    }
  }
  if (lastError) return { success: false, error: lastError, permanent: false };
  return { success: true };
}

const fileWriteHandler: CompensationHandler = async (action) => {
  return restoreFromStore(action, getSnapshotStore(), 'restore');
};
const fileEditHandler: CompensationHandler = async (action) => fileWriteHandler(action);
const fileAppendHandler: CompensationHandler = async (action) => fileWriteHandler(action);
const filePatchHandler: CompensationHandler = async (action) => fileWriteHandler(action);
const fileDeleteHandler: CompensationHandler = async (action) => fileWriteHandler(action);
const applyPatchHandler: CompensationHandler = async (action) => fileWriteHandler(action);
const codeFixerHandler: CompensationHandler = async (action) => fileWriteHandler(action);
const codeRefinerHandler: CompensationHandler = async (action) => fileWriteHandler(action);
const touchHandler: CompensationHandler = async (action) => fileWriteHandler(action);

const fileMoveHandler: CompensationHandler = async (action) => {
  // The snapshot was taken of BOTH source and dest before the move.
  // Restoring in REVERSE will: re-create dest (since it existed pre-move
  // as something else? actually dest didn't exist pre-move) → actually
  // we need to be careful here. For move, the snapshot of `dest` has
  // existed=false, so restoring deletes the dest. The snapshot of
  // `source` has existed=true (with original content), so restoring
  // re-creates the source file.
  //
  // Apply order: source-restore LAST (LIFO), so do it in the right order
  // by relying on the timestamp sort. SnapshotStore already sorts LIFO.
  return restoreFromStore(action, getSnapshotStore(), 'restore');
};

const fileCopyHandler: CompensationHandler = async (action) => {
  // copy only creates the dest. The snapshot of dest has existed=false;
  // restoring deletes the dest. The original source is unaffected.
  return restoreFromStore(action, getSnapshotStore(), 'delete');
};

const fileChmodHandler: CompensationHandler = async (action) => {
  // Snapshot captured mode; restoring writes back. If we didn't capture
  // a content blob (we did, since it was a regular file), restore rewrites
  // the content + applies the original mode.
  return restoreFromStore(action, getSnapshotStore(), 'restore');
};

const fileChownHandler: CompensationHandler = async (action) => {
  return fileChmodHandler(action);
};

const mkdirHandler: CompensationHandler = async (action) => {
  // For mkdir, the snapshot of the path has existed=false. Restoring
  // → "did not exist → delete (rmdir)" — but the dir might have contents
  // (forward action created it empty, but subsequent actions may have
  // populated it). Best effort: only rmdir if empty.
  return restoreFromStore(action, getSnapshotStore(), 'restore');
};

const rmdirHandler: CompensationHandler = async (action) => {
  // Snapshot captured the directory contents. Restoring re-creates the
  // directory but does NOT re-create the children (their content is not
  // captured at the directory level). Best effort.
  return restoreFromStore(action, getSnapshotStore(), 'restore');
};

const shellExecuteHandler: CompensationHandler = async (action) => {
  // Best-effort: restore all snapshotted paths.
  return restoreFromStore(action, getSnapshotStore(), 'restore');
};

/**
 * Compensate a "no such action" case: the action wasn't recorded (e.g.
 * read-only tool, or the forward side effect was never taken). Returning
 * success keeps the saga path moving.
 */
const noopHandler: CompensationHandler = async (_action) => {
  return { success: true, alreadyCompensated: true };
};

// ============================================================================
// Tool → handler map
// ============================================================================

export const FILESYSTEM_COMPENSATION_HANDLERS: Record<string, CompensationHandler> = {
  file_write: fileWriteHandler,
  file_edit: fileEditHandler,
  file_append: fileAppendHandler,
  file_patch: filePatchHandler,
  file_delete: fileDeleteHandler,
  file_move: fileMoveHandler,
  file_rename: fileMoveHandler,
  file_copy: fileCopyHandler,
  file_chmod: fileChmodHandler,
  file_chown: fileChownHandler,
  file_chgrp: fileChownHandler,
  touch: touchHandler,
  apply_patch: applyPatchHandler,
  code_fixer: codeFixerHandler,
  code_refiner: codeRefinerHandler,
  mkdir: mkdirHandler,
  mkdir_p: mkdirHandler,
  rmdir: rmdirHandler,
  // Shell: only compensable when a snapshot was taken (paths arg present).
  shell_execute: shellExecuteHandler,
  python_execute: shellExecuteHandler,
  // Pure reads → no compensation needed.
  file_read: noopHandler,
  file_list: noopHandler,
  file_search: noopHandler,
  glob: noopHandler,
  code_search: noopHandler,
};

// ============================================================================
// Tags for matching in the planner
// ============================================================================

export const FILESYSTEM_TOOL_TAGS: Record<string, string[]> = {
  file_write: ['fs', 'fs:create_or_overwrite', 'destructive'],
  file_edit: ['fs', 'fs:modify'],
  file_append: ['fs', 'fs:modify'],
  file_patch: ['fs', 'fs:modify'],
  file_delete: ['fs', 'fs:delete', 'destructive'],
  file_move: ['fs', 'fs:move', 'destructive'],
  file_rename: ['fs', 'fs:move', 'destructive'],
  file_copy: ['fs', 'fs:create', 'destructive'],
  file_chmod: ['fs', 'fs:metadata', 'low_risk'],
  file_chown: ['fs', 'fs:metadata', 'low_risk'],
  apply_patch: ['fs', 'fs:patch'],
  code_fixer: ['fs', 'fs:modify'],
  code_refiner: ['fs', 'fs:modify'],
  mkdir: ['fs', 'fs:mkdir'],
  rmdir: ['fs', 'fs:rmdir', 'destructive'],
  shell_execute: ['fs', 'fs:shell', 'destructive'],
  python_execute: ['fs', 'fs:python', 'destructive'],
};

// ============================================================================
// Registration helper
// ============================================================================

/**
 * Register all filesystem compensation handlers with the global ATR
 * scheduler. Idempotent — safe to call multiple times.
 */
export function registerFilesystemCompensation(): void {
  // Lazy import to avoid a circular dep at module load.

  const { getExecutionScheduler } =
    require('../../atr/scheduler') as typeof import('../../atr/scheduler');
  const scheduler = getExecutionScheduler();
  for (const [toolName, handler] of Object.entries(FILESYSTEM_COMPENSATION_HANDLERS)) {
    scheduler.registerCompensation(toolName, handler);
  }
}

// Suppress unused-import warning for statSync (kept for future use in
// the planner to detect symlink targets before snapshotting).
void statSync;
void dirname;
